import re

def detect_duplicate_tool_calls(messages):
    tool_calls = []
    for msg in messages:
        if msg.type == 'tool_use':
            tool_name = msg.name
            params = str(msg.input)
            tool_calls.append((tool_name, params))

    duplicates = []
    seen = {}
    for i, (name, params) in enumerate(tool_calls):
        key = f'{name}:{params}'
        if key in seen:
            duplicates.append({
                'type': 'duplicate_tool_call',
                'tool': name,
                'params': params,
                'first_occurence': seen[key],
                'current_index': i
            })
        seen[key] = i
    return duplicates
