function detectMemoryDrift(messages: any[]): MemoryDriftIssue[] {
  const issues: MemoryDriftIssue[] = [];
  const toolResults = new Map<string, any>();

  messages.forEach((msg, index) => {
    if (msg.type === 'tool_result') {
      toolResults.set(msg.tool_use_id, msg.content);
    }

    if (msg.type === 'user' || msg.type === 'assistant') {
      // Extract tool result references
      const toolIds = msg.content.match(/tool_use_id=["']([a-zA-Z0-9-]+)["']/g);
      if (toolIds) {
        toolIds.forEach(id => {
          const toolId = id.match(/([a-zA-Z0-9-]+)/)?.[1];
          if (toolId && !toolResults.has(toolId)) {
            issues.push({
              type: 'memory_drift',
              referenced_tool_id: toolId,
              message_index: index,
              description: `References non-existent tool result ${toolId}`
            });
          }
        });
      }
    }
  });

  return issues;
}
