        total_tokens += len(content) // 4  # Rough token estimation

    return {
        'overflow': total_tokens > max_tokens * 0.8,
        'current_tokens': total_tokens,
        'max_tokens': max_tokens,
        'utilization': total_tokens / max_tokens
