import time

class ToolMemoryCache:
    def __init__(self, ttl_seconds: int = 3600):
        self.cache: Dict[str, Dict[str, Any]] = {}
        self.ttl = ttl_seconds

    def store_result(self, tool_use_id: str, result: str, tool_name: str):
        self.cache[tool_use_id] = {
            'result': result,
            'summary': self._summarize_result(result),
            'tool_name': tool_name,
            'timestamp': time.time()
        }

    def get_summary(self, tool_use_id: str) -> Optional[str]:
        if tool_use_id in self.cache:
            cached = self.cache[tool_use_id]
            if time.time() - cached['timestamp'] < self.ttl:
                return f"[{cached['tool_name']}] {cached['summary']}"
        return None

    def _summarize_result(self, result: str) -> str:
        # Simple summarization - truncate and extract key info
        return result[:200] + '...' if len(result) > 200 else result

