function pruneConversation(messages: any[], maxTokens: number = 150000): any[] {
  let currentTokens = 0;
  const pruned: any[] = [];
  const criticalMessages: string[] = [];

  // First pass: identify critical tool results
  messages.forEach(msg => {
    if (msg.type === 'tool_result' || msg.role === 'user') {
      criticalMessages.push(msg.id || JSON.stringify(msg));
    }
  });

  // Second pass: prune while preserving critical messages
  for (let i = messages.length - 1; i >= 0; i--) {
    const msg = messages[i];
    const msgTokens = estimateTokens(msg.content || '');

    if (currentTokens + msgTokens > maxTokens && 
        !criticalMessages.includes(msg.id || JSON.stringify(msg))) {
      continue;
    }

    pruned.unshift(msg);
    currentTokens += msgTokens;
  }

  return pruned.slice(0, 100); // Safety limit
}

function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}
