from typing import Dict, Any, Optional

class AgentStateManager:
    def __init__(self):
        self.state: Dict[str, Any] = {
            'completed_tasks': [],
            'pending_tools': {},
            'key_facts': {},
            'decision_log': []
        }

    def extract_state_from_messages(self, messages):
        """Parse messages to extract structured state"""
        for msg in messages:
            if msg.type == 'tool_result':
                tool_id = msg.tool_use_id
                self.state['completed_tasks'].append({
                    'tool_id': tool_id,
                    'status': 'completed',
                    'timestamp': msg.timestamp
                })
            elif msg.type == 'user' and 'task' in msg.content.lower():
                self.state['decision_log'].append({
                    'type': 'user_task',
                    'content': msg.content[:100]
                })
        return self.state

    def inject_state_into_prompt(self) -> str:
        state_summary = f"""
AGENT STATE SUMMARY:
- Completed: {len(self.state['completed_tasks'])} tasks
- Key Facts: {len(self.state['key_facts'])} items
- Recent Decisions: {self.state['decision_log'][-3:]}
        """
        return state_summary

# Usage
